// Filtre: ignorer emails sans pièce jointe
const item = $input.first().json;
const hasAttachment = item.attachments && item.attachments.length > 0;
const isAutoReply = (item.subject || '').toLowerCase().includes('auto-reply');

if (!hasAttachment || isAutoReply) return [];

return [{ json: {
  from: item.from,
  subject: item.subject,
  attachments: item.attachments,
  text: item.text || '',
  date: item.date,
} }];

const email = $('🔍 Filtrer emails valides').first().json;
const posts = $('📋 Get Emission Posts').first().json;

const postList = posts.map(p =>
  `• [${p.id}] P${p.order_index} – ${p.name} (Scope ${p.scope})${p.category ? ' / ' + p.category : ''}`
).join('\n');

// Utiliser le texte de l'email + sujet comme contenu
const content = `Sujet: ${email.subject}\n\n${email.text}`.slice(0, 8000);

const prompt = `Tu es un expert en comptabilité carbone BC2025/ADEME.\n\nAnalyse ce message email et extrait les données d'activité carbone.\n\nPostes disponibles:\n${postList}\n\nRéponds UNIQUEMENT avec ce JSON:\n{"entries":[{"post_id":"UUID","description":"desc","quantity":0.0,"unit":"kWh","co2e_kgCO2e":null,"factor_hint":"factor"}]}`;

return [{ json: { prompt, content, posts, email } }];

const raw = $input.first().json.choices?.[0]?.message?.content ?? '';
const posts = $('📋 Get Emission Posts').first().json;
const userInfo = $('🔎 Chercher utilisateur Supabase').first().json?.[0];

const match = raw.match(/\{[\s\S]*\}/);
let parsed = { entries: [] };
try { parsed = JSON.parse(match?.[0] ?? '{"entries":[]}'); } catch {}

const validIds = new Set(posts.map(p => p.id));
const postMap = Object.fromEntries(posts.map(p => [p.id, p]));

const entries = (parsed.entries ?? [])
  .filter(e => validIds.has(e.post_id) && e.quantity > 0)
  .map(e => ({
    post_id: e.post_id,
    post_name: postMap[e.post_id]?.name ?? '',
    description: e.description,
    quantity: e.quantity,
    unit: e.unit,
    co2e_kgCO2e: e.co2e_kgCO2e,
    factor_hint: e.factor_hint,
  }));

return [{ json: { entries, userInfo, totalEntries: entries.length } }];

// Préparer les insertions Supabase
const { entries, userInfo } = $input.first().json;

if (!entries.length || !userInfo?.id) return [];

// Format pour insertion Supabase (study_id sera récupéré séparément)
return entries.map(e => ({ json: {
  emission_post_id: e.post_id,
  description: `[Email auto-import] ${e.description}`,
  quantity: e.quantity,
  unit: e.unit,
  co2e_calculated: e.co2e_kgCO2e,
  contributor_id: userInfo.id,
  status: 'pending_review',
  source: 'n8n_email',
} }));
